import { FormEvent, ReactNode, useCallback, useEffect, useMemo, useState } from "react";
import { buildLocalizedPath, isEnglish } from "../../lib/navigation/runtime";
import { AdminPageShell } from "../admin-entry/AdminPageShell";
import { GovernanceCompressionNav } from "../admin-system/GovernanceCompressionNav";
import { DeliveryControlPanel } from "./DeliveryControlPanel";
import { ProcessDesignMap } from "./ProcessDesignMap";
import { CustomerWorkDevelopmentDashboard } from "./CustomerWorkDevelopmentDashboard";

type Row = Record<string, unknown>;
type Payload = { deliveryQueue?:Row[]; deliverySummary?:Row; workTypes?:Row[]; actors: Row[]; assignments: Row[]; actorAccountReadiness?:Row[]; processes: Row[]; steps: Row[]; cases: Row[]; runs: Row[]; artifacts:Row[]; developmentRules:Row[]; developmentJobs:Row[]; developmentEvents:Row[]; jobDependencies:Row[]; qualityGates:Row[]; qualityGateResults:Row[]; processDevelopmentProgress:Row[]; screenTypes:Row[]; referenceAssets:Row[]; automationMetrics:Row[]; screenDevelopmentGates:Row[]; processExecutions:Row[]; processExecutionEvents:Row[]; commonFeaturePackages?:Row[]; screenFeatureBindings?:Row[]; featureInstallations?:Row[]; designValidationRuns?:Row[]; screenBlueprints?:Row[]; generationBatches?:Row[]; professionalReadiness?:Row[]; professionalSummary?:Row; professionalScreenContracts?:Row[]; professionalScreenSummary?:Row; professionalFactoryRuns?:Row[]; screenAssetAssemblies?:Row[]; projectRegistrationCoverage?:Row[]; projectRegistrationSummary?:Row; customerJourneyGaps?:Row[]; customerJourneySummary?:Row; actorProcessMenus?:Row[]; actorProcessMenuSummary?:Row; backendProcessReadiness?:Row[]; projectCompletionRuns?:Row[]; referenceSummary?:Row; summary?: Row };
type DesignInventory={counts:Row;themes:Row[];sections:Row[];components:Row[];duplicates:Row[];recentPreflights:Row[]};
const empty: Payload = { workTypes:[], actors: [], assignments: [], processes: [], steps: [], cases: [], runs: [], artifacts:[], developmentRules:[], developmentJobs:[], developmentEvents:[], jobDependencies:[], qualityGates:[], qualityGateResults:[], processDevelopmentProgress:[], screenTypes:[], referenceAssets:[], automationMetrics:[], screenDevelopmentGates:[], processExecutions:[], processExecutionEvents:[] };
const value = (row: Row, key: string) => String(row[key] ?? "");
const fieldClass = "h-11 w-full rounded-lg border border-slate-300 bg-white px-3 text-sm focus:border-[#246beb] focus:outline-none focus:ring-2 focus:ring-blue-100";

export function ActorProcessGovernancePage() {
  const en = isEnglish();
  const base = buildLocalizedPath("/admin/api/system/actor-process", "/en/admin/api/system/actor-process");
  const [data, setData] = useState<Payload>(empty);
  const [tab, setTab] = useState("work-dashboard");
  const [processFilter, setProcessFilter] = useState(() => new URLSearchParams(location.search).get("process") || "");
  const [preflightProcess,setPreflightProcess]=useState("");
  const [preflightStep,setPreflightStep]=useState("");
  const [executionProcess,setExecutionProcess]=useState("EMISSION_PROJECT");
  const [executionId,setExecutionId]=useState("");
  const [executionStartActor,setExecutionStartActor]=useState("COMPANY_MANAGER");
  const [factoryProcess,setFactoryProcess]=useState("EMISSION_PROJECT");
  const [factoryActor,setFactoryActor]=useState("COMPANY_MANAGER");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);
  const [design,setDesign]=useState<DesignInventory>({counts:{},themes:[],sections:[],components:[],duplicates:[],recentPreflights:[]});

  const load = useCallback(async () => {
    try {
      const response = await fetch(base, { credentials: "include" });
      const body = await response.json();
      if (!response.ok) throw new Error(body.message || "조회에 실패했습니다.");
      setData(body);
      setError("");
    } catch (reason) { setError(reason instanceof Error ? reason.message : "조회에 실패했습니다."); }
  }, [base]);
  useEffect(() => { void load(); }, [load]);
  useEffect(()=>{
    const process=preflightProcess||value(data.processes[0]||{},"processCode");
    if(process&&!preflightProcess)setPreflightProcess(process);
    const steps=data.steps.filter(row=>value(row,"processCode")===process);
    if(steps.length&&!steps.some(row=>value(row,"stepCode")===preflightStep))setPreflightStep(value(steps[0],"stepCode"));
  },[data.processes,data.steps,preflightProcess,preflightStep]);
  const loadDesign=useCallback(async()=>{const response=await fetch(`${base}/design-assets`,{credentials:"include"}),body=await response.json();if(!response.ok)throw new Error(body.message||"디자인 자산 조회 실패");setDesign(body)},[base]);
  useEffect(()=>{void loadDesign().catch(reason=>setError(reason instanceof Error?reason.message:String(reason)))},[loadDesign]);

  async function post(path: string, body: Record<string, unknown>) {
    setBusy(true); setError(""); setMessage("");
    try {
      const response = await fetch(`${base}/${path}`, { method: "POST", credentials: "include", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
      const result = await response.json();
      if (!response.ok) throw new Error(result.message || "저장에 실패했습니다.");
      setMessage(path === "standard-pack"
        ? `표준 업무팩을 반영했습니다. 프로세스 ${result.processes ?? 0}개, 단계 ${result.steps ?? 0}개, 시나리오 ${result.cases ?? 0}개가 준비되었습니다.`
        : path === "development/direct"
          ? (result.changed ? `${result.processCode} 설계 변경을 개발 큐까지 직접 반영했습니다. 상태: ${result.status}` : `${result.processCode} 설계 변경이 없어 기존 개발 큐를 즉시 재사용합니다.`)
        : path === "development/bootstrap-process"
          ? `${result.processCode} 자동공장 준비가 완료되었습니다. 시나리오 ${result.scenarioCount ?? 0}개, 개발 작업 ${result.totalJobs ?? 0}개, 유효 화면 ${result.validScreens ?? 0}개를 연결했습니다. ${result.blockedStepCount ? `설계·시안 보강 대기 ${result.blockedStepCount}단계` : "모든 단계 실행 가능"}.`
          : "저장되었습니다.");
      await load();
    } catch (reason) { setError(reason instanceof Error ? reason.message : "저장에 실패했습니다."); }
    finally { setBusy(false); }
  }
  async function submit(event: FormEvent<HTMLFormElement>, path: string) {
    event.preventDefault();
    const form = event.currentTarget;
    await post(path, Object.fromEntries(new FormData(form).entries()));
    if (!error) form.reset();
  }

  const selectedSteps = useMemo(() => data.steps.filter(row => !processFilter || value(row, "processCode") === processFilter), [data.steps, processFilter]);
  const selectedCases = useMemo(() => data.cases.filter(row => !processFilter || value(row, "processCode") === processFilter), [data.cases, processFilter]);
  const readyCount = Number(data.summary?.readyCount ?? 0);
  const readiness = Number(data.summary?.readinessPercent ?? 0);
  const processCompletion=(row:Row)=>{const artifacts=Number(row.artifactCount||0),verified=Number(row.verifiedArtifactCount||0),cases=Number(row.caseCount||0),approved=Number(row.approvedCaseCount||0),steps=Number(row.stepCount||0);return artifacts>0&&cases>=5&&steps>0?Math.round(((verified/artifacts)*70+(approved/cases)*30)):0};
  const filteredArtifacts=useMemo(()=>data.artifacts.filter(row=>!processFilter||value(row,"processCode")===processFilter),[data.artifacts,processFilter]);
  const tabs = [["process-map", "전체 프로세스 설계도"], ["overview", "전체 현황"], ["references", "레퍼런스 자동설계"], ["generation", "대량 화면 생성"], ["actors", "액터"], ["assignments", "계정 배정"], ["account-readiness", "액터 계정 검증"], ["work-types", "업무 종류"], ["processes", "프로세스"], ["steps", "단계"], ["execution", "종단간 업무 실행"], ["automation", "프로세스 자동개발"], ["artifacts", "개발 산출물"], ["design", "디자인 사전검사"], ["rules", "개발 규칙"], ["simulation", "시나리오·실행"]];

  return <AdminPageShell breadcrumbs={[{ label: en ? "Home" : "홈", href: buildLocalizedPath("/admin/", "/en/admin/") }, { label: en ? "System" : "시스템 관리" }, { label: en ? "Actor & Process" : "액터·프로세스 관리" }]} title={en ? "Actor & Process Governance" : "액터·프로세스 관리"}>
    <GovernanceCompressionNav activeId="actor-process" en={en} />
    <div className="space-y-5">
      <section className="rounded-2xl bg-gradient-to-r from-[#052b57] to-[#174ea6] p-6 text-white shadow-sm">
        <div className="flex flex-col gap-5 xl:flex-row xl:items-end xl:justify-between">
          <div><p className="text-sm font-bold text-blue-200">PROCESS CONTROL PLANE</p><h2 className="mt-1 text-2xl font-black">액터에서 테스트까지, 개발 전 업무 설계를 한곳에서 관리합니다.</h2><p className="mt-2 max-w-3xl text-sm text-blue-50">계정과 프로젝트별 역할, 상태 전이, 완료 조건, 예외·권한·격리·복구 시나리오가 승인되어야 개발 준비 상태가 됩니다.</p></div>
          <button disabled={busy} onClick={() => void post("standard-pack", {})} className="h-12 rounded-xl bg-white px-5 font-black text-[#174ea6] shadow disabled:opacity-50">{busy ? "반영 중..." : "표준 업무팩 일괄 등록"}</button>
        </div>
        <div className="mt-6 grid gap-3 sm:grid-cols-2 xl:grid-cols-5">{[["액터", data.actors.length], ["계정 배정", data.assignments.length], ["프로세스", data.processes.length], ["시나리오", data.cases.length], ["개발 준비", `${readyCount}/${data.processes.length}`]].map(([label, number]) => <div key={String(label)} className="rounded-xl bg-white/10 p-4"><span className="text-sm text-blue-100">{label}</span><strong className="mt-1 block text-2xl">{number}</strong></div>)}</div>
      </section>
      {message && <p className="rounded-xl border border-emerald-200 bg-emerald-50 p-4 font-bold text-emerald-800">{message}</p>}
      {error && <p className="rounded-xl border border-red-200 bg-red-50 p-4 font-bold text-red-700">{error}</p>}
      <button onClick={() => setTab("work-dashboard")} className={`rounded-lg px-4 py-3 text-sm font-bold ${tab === "work-dashboard" ? "bg-[#246beb] text-white" : "border bg-white text-slate-700 hover:bg-slate-50"}`}>{en ? "Customer Work Board" : "고객 업무 개발 현황판"}</button>
      <button onClick={() => setTab("delivery")} className={`rounded-lg px-4 py-3 text-sm font-bold ${tab === "delivery" ? "bg-[#246beb] text-white" : "border bg-white text-slate-700 hover:bg-slate-50"}`}>{en ? "Delivery Control" : "개발 실행 큐"}</button>
      <nav className="flex flex-wrap gap-2">{[["professional", en ? "Professional Readiness" : "전문가 준비도"], ["common-features", en ? "Reusable Capabilities" : "공통 특수기능"], ["menu-bindings", en ? "Actor Process Menus" : "액터·프로세스 메뉴"], ["customer-journey", en ? "Customer Journey Gate" : "고객 여정 자동검사"], ["registration-coverage", en ? "Project Registration Requirements" : "프로젝트 등록 요건"], ["screen-contracts", en ? "Screen Completion Contracts" : "화면 완성 계약"], ...tabs].map(([id, name]) => <button key={id} onClick={() => setTab(id)} className={`rounded-lg px-4 py-3 text-sm font-bold ${tab === id ? "bg-[#246beb] text-white" : "border bg-white text-slate-700 hover:bg-slate-50"}`}>{name}</button>)}</nav>

      {tab === "work-dashboard" && <CustomerWorkDevelopmentDashboard actors={data.actors} actorReadiness={data.actorAccountReadiness ?? []} artifacts={data.artifacts} assignments={data.assignments} backendReadiness={data.backendProcessReadiness ?? []} busy={busy} cases={data.cases} completionRuns={data.projectCompletionRuns ?? []} deliveryQueue={data.deliveryQueue ?? []} dependencies={data.jobDependencies} jobs={data.developmentJobs} journeyGaps={data.customerJourneyGaps ?? []} onPost={post} processes={data.processes} progress={data.processDevelopmentProgress} runs={data.runs} screenContracts={data.professionalScreenContracts ?? []} steps={data.steps} />}
      {tab === "delivery" && <DeliveryControlPanel rows={data.deliveryQueue ?? []} summary={data.deliverySummary ?? {}} onSelect={code=>{setProcessFilter(code);setTab("automation")}} />}
      {tab === "process-map" && <ProcessDesignMap actors={data.actors} artifacts={data.artifacts} busy={busy} cases={data.cases} jobs={data.developmentJobs} onDirectDevelop={code=>void post("development/direct",{processCode:code})} onProcessChange={setProcessFilter} processCode={processFilter} processes={data.processes} steps={data.steps}/>}
      {tab === "professional" && <>
        <Form onSubmit={event=>void submit(event,"professional-factory/execute")} cols="lg:grid-cols-3">
          <Field label={en?"Process":"자동 개발 프로세스"}><select className={fieldClass} name="processCode" value={factoryProcess} onChange={event=>{setFactoryProcess(event.target.value);const actor=value(data.steps.find(row=>value(row,"processCode")===event.target.value)||{},"actorCode");if(actor)setFactoryActor(actor)}}>{data.processes.map(row=><option key={value(row,"processCode")} value={value(row,"processCode")}>{value(row,"processName")} ({value(row,"processCode")})</option>)}</select></Field>
          <Field label={en?"Participating actor":"참여 액터"}><select className={fieldClass} name="actorCode" value={factoryActor} onChange={event=>setFactoryActor(event.target.value)}>{data.actors.filter(actor=>data.steps.some(step=>value(step,"processCode")===factoryProcess&&value(step,"actorCode")===value(actor,"actorCode"))).map(row=><option key={value(row,"actorCode")} value={value(row,"actorCode")}>{value(row,"actorName")} ({value(row,"actorCode")})</option>)}</select></Field>
          <SaveButton busy={busy} label={en?"Run professional factory":"전문 업무팩 자동 개발"}/>
        </Form>
        <ProfessionalReadinessPanel en={en} rows={data.professionalReadiness ?? []} summary={data.professionalSummary ?? {}} />
        <Table heads={en?["Run","Process","Actor","Status","Menus","Screens","Scenarios","Jobs","Blocked"]:["실행","프로세스","액터","상태","메뉴","화면","시나리오","개발 작업","차단 단계"]} rows={(data.professionalFactoryRuns??[]).map(row=>[value(row,"runId"),value(row,"processCode"),value(row,"requestedActorCode"),value(row,"runStatus"),value(row,"menuCount"),value(row,"screenCount"),value(row,"scenarioCount"),value(row,"developmentJobCount"),value(row,"blockedStepCount")])}/>
      </>}
      {tab === "screen-contracts" && <ProfessionalScreenContractPanel assemblies={data.screenAssetAssemblies??[]} en={en} rows={data.professionalScreenContracts ?? []} summary={data.professionalScreenSummary ?? {}} />}
      {tab === "common-features" && <CommonFeaturePackagePanel bindings={data.screenFeatureBindings??[]} busy={busy} installations={data.featureInstallations??[]} onPost={post} packages={data.commonFeaturePackages??[]} processCode={processFilter} runs={data.designValidationRuns??[]} />}
      {tab === "registration-coverage" && <ProjectRegistrationCoveragePanel en={en} rows={data.projectRegistrationCoverage ?? []} summary={data.projectRegistrationSummary ?? {}} />}
      {tab === "customer-journey" && <CustomerJourneyGatePanel en={en} rows={data.customerJourneyGaps ?? []} summary={data.customerJourneySummary ?? {}} />}
      {tab === "menu-bindings" && <ActorProcessMenuPanel en={en} rows={data.actorProcessMenus ?? []} summary={data.actorProcessMenuSummary ?? {}} />}

      {tab === "references" && <><section className="grid gap-4 sm:grid-cols-4">{[["발견 자산","assetCount"],["분석 완료","analyzedCount"],["연결 프로세스","mappedProcesses"],["평균 신뢰도","averageConfidence"]].map(([label,key])=><div key={key} className="rounded-xl border bg-white p-4"><span className="text-xs font-bold text-slate-500">{label}</span><strong className="mt-1 block text-2xl text-[#052b57]">{value(data.referenceSummary||{},key)}{key==="averageConfidence"?"%":""}</strong></div>)}</section><section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="font-black text-[#052b57]">근거 기반 자동설계</h3><p className="mt-1 text-sm text-slate-700">레퍼런스 파일명·형식과 기존 메뉴·페이지·API·DB를 화면 유형 및 업무 도메인으로 분류합니다. 액터·프로세스·정상/예외/권한/격리/복구 기대값을 멱등 등록하고, 구현 차이 분석 작업을 자동 승인 큐에 넣습니다.</p></section><Form onSubmit={event=>void submit(event,"references/scan")} cols="lg:grid-cols-4"><div className="lg:col-span-3"><Field label="레퍼런스 정본 경로"><input className={fieldClass} name="rootPath" defaultValue="/opt/reference" required/></Field></div><SaveButton busy={busy} label="전수조사·자동설계 시작"/></Form><Table heads={["화면 유형","필수 섹션","자동 테스트 기대값","개발 가중치"]} rows={data.screenTypes.map(row=>[`${value(row,"screenTypeName")} (${value(row,"screenType")})`,value(row,"requiredSections"),value(row,"testExpectations"),value(row,"developmentWeight")])}/><Table heads={["레퍼런스","형식","도메인","화면 유형","프로세스","상태","신뢰도"]} rows={data.referenceAssets.map(row=>[value(row,"sourceName"),value(row,"sourceType"),value(row,"domainCode"),value(row,"screenType"),value(row,"processCode"),value(row,"analysisStatus"),`${value(row,"confidence")}%`])}/></>}

      {tab === "generation" && <>
        <button className="h-12 rounded-xl bg-[#0f7b49] px-5 font-black text-white disabled:opacity-50" disabled={busy} onClick={()=>void post("generation/compile-and-queue",{processCode:"",maxScreens:1000})} type="button">1,000개 화면 컴파일·구현 큐 일괄 등록</button>
        <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="text-lg font-black text-[#052b57]">기존 전체 화면 동일 방식 전환</h3><p className="mt-1 text-sm leading-6 text-slate-700">기존 URL과 업무 기능은 보존하고 모든 화면을 액터·프로세스·5종 테스트·KRDS 디자인 계약에 편입합니다. 숨김 종속 화면도 포함하며 전용 구현을 공통 빈 화면으로 덮어쓰지 않습니다.</p><button className="mt-4 rounded-lg bg-[#052b57] px-4 py-3 font-bold text-white disabled:opacity-50" disabled={busy} onClick={()=>void post("generation/adopt-existing",{maxScreens:1000})} type="button">기존 화면 최대 1,000개 일괄 전환</button></section>
        <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="font-black text-[#052b57]">액터·프로세스 기반 화면 설계 컴파일러</h3><p className="mt-2 text-sm leading-6 text-slate-700">프로세스 단계의 사용자·관리자 화면 요구를 최대 1,000개까지 단일 화면 설계 원본으로 컴파일합니다. 액터, 경로, 화면 유형, KRDS 템플릿, 정상·예외·권한·격리·복구 테스트 추적성이 모두 유효한 설계만 기존 자동개발 작업 큐로 전달됩니다.</p></section>
        <Form onSubmit={event=>void submit(event,"generation/compile")} cols="lg:grid-cols-4"><Field label="프로세스 범위"><select className={fieldClass} name="processCode"><option value="">전체 프로세스</option>{data.processes.map(row=><option key={value(row,"processCode")} value={value(row,"processCode")}>{value(row,"processName")}</option>)}</select></Field><Field label="최대 화면 수"><input className={fieldClass} type="number" min="1" max="1000" name="maxScreens" defaultValue="1000" required/></Field><Field label="실행 방식"><select className={fieldClass} name="dryRun" defaultValue="true"><option value="true">설계·검증만</option><option value="false">설계 후 큐 준비</option></select></Field><SaveButton busy={busy} label="최대 1,000개 설계 컴파일"/></Form>
        <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{[["화면 설계",data.screenBlueprints?.length||0],["생성 배치",data.generationBatches?.length||0],["검증 통과",(data.screenBlueprints||[]).filter(row=>value(row,"validationStatus")==="VALID").length],["검토 필요",(data.screenBlueprints||[]).filter(row=>value(row,"validationStatus")!=="VALID").length]].map(([label,metric])=><article className="rounded-xl border bg-white p-4" key={String(label)}><span className="text-sm font-bold text-slate-500">{label}</span><strong className="mt-1 block text-2xl text-[#052b57]">{metric}</strong></article>)}</section>
        <Table heads={["배치","범위","요청","컴파일","유효","오류","큐","상태","실행"]} rows={(data.generationBatches||[]).map(row=>[value(row,"batchCode"),value(row,"processCode")||"전체",value(row,"requestedCount"),value(row,"compiledCount"),value(row,"validCount"),value(row,"invalidCount"),value(row,"queuedCount"),value(row,"batchStatus"),value(row,"batchStatus")==="COMPILED"?"아래 큐 등록 사용":"-"])}/>
        <div className="flex flex-wrap gap-2">{(data.generationBatches||[]).slice(0,5).map(row=><a className="rounded-lg border border-[#246beb] bg-white px-4 py-3 font-bold text-[#246beb]" download={`${value(row,"batchCode")}.json`} href={`${base}/generation/batches/${value(row,"batchId")}/export`} key={`export-${value(row,"batchId")}`}>{value(row,"batchCode")} 설계 JSON 내보내기</a>)}</div>
        {(data.generationBatches||[]).some(row=>value(row,"batchStatus")==="COMPILED")&&<div className="flex flex-wrap gap-2">{(data.generationBatches||[]).filter(row=>value(row,"batchStatus")==="COMPILED").slice(0,3).map(row=><button className="rounded-lg bg-[#052b57] px-4 py-3 font-bold text-white disabled:opacity-50" disabled={busy} key={value(row,"batchId")} onClick={()=>void post("generation/queue",{batchId:value(row,"batchId")})} type="button">{value(row,"batchCode")} 검증 설계 큐 등록</button>)}</div>}
        <Table heads={["설계 코드","프로세스·단계","액터","대상","화면","경로","유형·템플릿","검증"]} rows={(data.screenBlueprints||[]).map(row=>[value(row,"blueprintCode"),`${value(row,"processCode")} / ${value(row,"stepCode")}`,value(row,"actorCode"),value(row,"audience"),value(row,"pageName"),value(row,"routePath"),`${value(row,"screenType")} / ${value(row,"templateCode")}`,value(row,"validationStatus")+(value(row,"validationMessage")?` · ${value(row,"validationMessage")}`:"")])}/>
      </>}

      {tab === "execution" && <>
        <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="text-lg font-black text-[#052b57]">액터·프로세스 종단간 실행</h3><p className="mt-1 text-sm leading-6 text-slate-700">모든 함수는 테넌트·프로젝트·프로세스·실행 ID·단계·액터·명령·멱등키를 검증합니다. 현재 단계의 담당 액터만 명령을 실행할 수 있고 다음 화면과 액터가 서버 상태로 결정됩니다.</p></section>
        <Form onSubmit={event=>void submit(event,"executions/start")} cols="lg:grid-cols-5"><Field label="테넌트"><input className={fieldClass} name="tenantId" defaultValue="DEFAULT" required/></Field><Field label="프로젝트"><input className={fieldClass} name="projectId" defaultValue="PRJ-2026-001" required/></Field><Field label="프로세스"><select className={fieldClass} name="processCode" value={executionProcess} onChange={event=>{const process=event.target.value;setExecutionProcess(process);const first=data.steps.filter(row=>value(row,"processCode")===process).sort((a,b)=>Number(a.stepOrder)-Number(b.stepOrder))[0];if(first)setExecutionStartActor(value(first,"actorCode"));}}>{data.processes.map(row=><option key={value(row,"processCode")} value={value(row,"processCode")}>{value(row,"processName")}</option>)}</select></Field><Field label="시작 액터"><select className={fieldClass} name="actorCode" value={executionStartActor} onChange={event=>setExecutionStartActor(event.target.value)}>{data.actors.map(row=><option key={value(row,"actorCode")} value={value(row,"actorCode")}>{value(row,"actorName")} ({value(row,"actorCode")})</option>)}</select></Field><SaveButton busy={busy} label="업무 실행 시작"/></Form>
        <Form onSubmit={event=>void submit(event,`executions/${executionId}/commands`)} cols="lg:grid-cols-4"><Field label="실행 ID"><input className={fieldClass} name="executionIdDisplay" value={executionId} onChange={event=>setExecutionId(event.target.value)} required/></Field><Field label="테넌트"><input className={fieldClass} name="tenantId" defaultValue="DEFAULT" required/></Field><Field label="프로젝트"><input className={fieldClass} name="projectId" defaultValue="PRJ-2026-001" required/></Field><Field label="프로세스"><select className={fieldClass} name="processCode" value={executionProcess} onChange={event=>setExecutionProcess(event.target.value)}>{data.processes.map(row=><option key={value(row,"processCode")} value={value(row,"processCode")}>{value(row,"processCode")}</option>)}</select></Field><Field label="현재 단계"><select className={fieldClass} name="stepCode">{data.steps.filter(row=>value(row,"processCode")===executionProcess).map(row=><option key={value(row,"stepCode")} value={value(row,"stepCode")}>{value(row,"stepName")}</option>)}</select></Field><Field label="수행 액터"><select className={fieldClass} name="actorCode">{data.actors.map(row=><option key={value(row,"actorCode")} value={value(row,"actorCode")}>{value(row,"actorName")}</option>)}</select></Field><Field label="명령"><select className={fieldClass} name="commandCode">{data.steps.filter(row=>value(row,"processCode")===executionProcess).map(row=><option key={value(row,"commandCode")} value={value(row,"commandCode")}>{value(row,"commandCode")}</option>)}</select></Field><Field label="멱등키"><input className={fieldClass} name="idempotencyKey" defaultValue={`UI-${Date.now()}`} required/></Field><div className="lg:col-span-3"><Field label="요청 JSON"><input className={fieldClass} name="requestJson" defaultValue="{}" required/></Field></div><SaveButton busy={busy} label="현재 단계 명령 실행"/></Form>
        <Table heads={["실행 ID","프로젝트","프로세스","현재 단계","현재 상태","상태","시작 액터","시작 시각"]} rows={data.processExecutions.map(row=>[value(row,"executionId"),value(row,"projectId"),value(row,"processCode"),value(row,"currentStepCode"),value(row,"currentState"),value(row,"executionStatus"),value(row,"initiatedByActor"),value(row,"startedAt")])}/>
        <Table heads={["이벤트","실행 ID","단계","액터","명령","상태 전이","멱등키","실행 시각"]} rows={data.processExecutionEvents.map(row=>[value(row,"eventId"),value(row,"executionId"),value(row,"stepCode"),value(row,"actorCode"),value(row,"commandCode"),`${value(row,"fromState")} → ${value(row,"toState")}`,value(row,"idempotencyKey"),value(row,"executedAt")])}/>
      </>}

      {tab === "automation" && <>
        <ProcessFilter processes={data.processes} value={processFilter} onChange={setProcessFilter}/>
        <section className="rounded-2xl border border-emerald-200 bg-emerald-50 p-5">
          <h3 className="text-lg font-black text-[#052b57]">프로세스 개발 자동 준비</h3>
          <p className="mt-1 text-sm leading-6 text-slate-700">선택한 프로세스의 정상·예외·권한·격리·복구 시나리오, 단계별 DB·API·화면·알림·테스트 작업, 화면 설계와 실행 큐를 한 트랜잭션으로 멱등 생성합니다.</p>
          <div className="mt-4 flex flex-col gap-3 sm:flex-row sm:items-end">
            <Field label="자동 준비할 프로세스"><select className={`${fieldClass} sm:min-w-80`} value={processFilter} onChange={event=>setProcessFilter(event.target.value)}><option value="">프로세스를 선택하십시오</option>{data.processes.map(row=><option key={value(row,"processCode")} value={value(row,"processCode")}>{value(row,"processName")} ({value(row,"processCode")})</option>)}</select></Field>
            <button className="h-11 rounded-lg bg-[#0f7b49] px-5 font-black text-white disabled:cursor-not-allowed disabled:opacity-50" disabled={busy||!processFilter} onClick={()=>void post("development/direct",{processCode:processFilter})} type="button">설계부터 개발 큐까지 즉시 반영</button>
          </div>
        </section>
        <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="text-lg font-black text-[#052b57]">상세 절차를 넣으면 개발 작업을 자동 도출합니다</h3><p className="mt-1 text-sm text-slate-700">원하는 순서에 절차를 삽입하면 후속 순서를 재계산하고 DB·API·백엔드·사용자 화면·관리자 화면·알림·테스트·통합 작업과 필수 산출물을 생성합니다. 상위 단계 코드를 지정하면 서브 절차가 됩니다.</p></section>
        <Form onSubmit={event=>void submit(event,"processes")} cols="lg:grid-cols-4"><Field label="서브프로세스 코드"><input className={fieldClass} name="processCode" required/></Field><Field label="서브프로세스명"><input className={fieldClass} name="processName" required/></Field><Field label="상위 프로세스"><select className={fieldClass} name="parentProcessCode" required>{data.processes.map(row=><option key={value(row,"processCode")}>{value(row,"processCode")}</option>)}</select></Field><Field label="도메인"><input className={fieldClass} name="domainCode" required/></Field><Field label="버전"><input className={fieldClass} name="version" defaultValue="1.0.0" required/></Field><Field label="자동화 방식"><select className={fieldClass} name="automationMode"><option>ASSISTED</option><option>AUTOMATIC</option><option>MANUAL</option></select></Field><div className="lg:col-span-2"><Field label="목표"><input className={fieldClass} name="goal" required/></Field></div><div className="lg:col-span-2"><Field label="시작 조건"><input className={fieldClass} name="startCondition" required/></Field></div><div className="lg:col-span-2"><Field label="완료 조건"><input className={fieldClass} name="completionCondition" required/></Field></div><SaveButton busy={busy} label="서브프로세스 등록"/></Form>
        <Form onSubmit={event=>void submit(event,"steps")} cols="lg:grid-cols-4">
          <Field label="프로세스"><select className={fieldClass} name="processCode" required>{data.processes.map(row=><option key={value(row,"processCode")}>{value(row,"processCode")}</option>)}</select></Field><Field label="삽입 순서"><input className={fieldClass} type="number" min="1" name="stepOrder" required/></Field><Field label="절차 코드"><input className={fieldClass} name="stepCode" required/></Field><Field label="절차명"><input className={fieldClass} name="stepName" required/></Field>
          <Field label="상위 단계 코드"><input className={fieldClass} name="parentStepCode" placeholder="비우면 최상위"/></Field><Field label="절차 유형"><select className={fieldClass} name="stepType"><option>TASK</option><option>SUB_PROCESS</option><option>DECISION</option><option>APPROVAL</option><option>AUTOMATION</option><option>EVENT</option></select></Field><Field label="수행 액터"><select className={fieldClass} name="actorCode">{data.actors.map(row=><option key={value(row,"actorCode")} value={value(row,"actorCode")}>{value(row,"actorName")}</option>)}</select></Field><Field label="명령 코드"><input className={fieldClass} name="commandCode" required/></Field>
          <Field label="이전 상태"><input className={fieldClass} name="fromState" required/></Field><Field label="다음 상태"><input className={fieldClass} name="toState" required/></Field><div className="lg:col-span-2"><Field label="상세 요구사항"><textarea className={`${fieldClass} h-24 py-2`} name="requirementText" required/></Field></div><div className="lg:col-span-2"><Field label="완료 규칙"><input className={fieldClass} name="completionRule" required/></Field></div>
          <Field label="입력 계약 JSON"><input className={fieldClass} name="inputContract" defaultValue="{}"/></Field><Field label="출력 계약 JSON"><input className={fieldClass} name="outputContract" defaultValue="{}"/></Field><Field label="사용자 화면 경로"><input className={fieldClass} name="userPath"/></Field><Field label="관리자 화면 경로"><input className={fieldClass} name="adminPath"/></Field><Field label="API 계약"><input className={fieldClass} name="apiContract"/></Field>
          <div className="lg:col-span-3 grid gap-3 sm:grid-cols-2 lg:grid-cols-5">{[["requiresDatabase","DB"],["requiresApi","API·백엔드"],["requiresUserPage","사용자 화면"],["requiresAdminPage","관리자 화면"],["requiresNotification","알림"]].map(([name,label])=><label key={name} className="flex min-h-11 items-center gap-2 rounded-lg border bg-white px-3 text-sm font-bold"><input type="checkbox" name={name} value="true"/>{label}</label>)}</div><SaveButton busy={busy} label="절차 삽입·개발계획 생성"/>
        </Form>
        <section className="rounded-2xl border border-amber-300 bg-amber-50 p-5"><h3 className="text-lg font-black text-amber-950">화면 자동개발 사전검사</h3><p className="mt-1 text-sm leading-6 text-amber-900">화면 설계·기능·완료 기준, 선택된 HTML 시안, 액터 계약, 정상·예외·권한·격리·복구 테스트를 모두 통과해야 개발계획을 승인할 수 있습니다. 테마·섹션·컴포넌트 사전검사 여부도 함께 기록합니다.</p></section>
        <Form onSubmit={event=>void submit(event,"development/preflight")} cols="lg:grid-cols-4"><Field label="사전검사 프로세스"><select className={fieldClass} name="processCode" required value={preflightProcess} onChange={event=>setPreflightProcess(event.target.value)}>{data.processes.map(row=><option key={value(row,"processCode")}>{value(row,"processCode")}</option>)}</select></Field><Field label="검사할 절차"><select className={fieldClass} name="stepCode" required value={preflightStep} onChange={event=>setPreflightStep(event.target.value)}>{data.steps.filter(row=>value(row,"processCode")===preflightProcess).map(row=><option key={`${value(row,"processCode")}-${value(row,"stepCode")}`} value={value(row,"stepCode")}>{value(row,"stepName")}</option>)}</select></Field><div className="lg:col-span-2 flex items-end"><SaveButton busy={busy} label="설계·시안·액터·테스트 검사"/></div></Form>
        <Form onSubmit={event=>void submit(event,"development/approve")} cols="lg:grid-cols-4"><Field label="개발계획 승인 프로세스"><select className={fieldClass} name="processCode" required>{data.processes.map(row=><option key={value(row,"processCode")}>{value(row,"processCode")}</option>)}</select></Field><Field label="승인할 절차"><select className={fieldClass} name="stepCode" required>{selectedSteps.map(row=><option key={value(row,"stepCode")} value={value(row,"stepCode")}>{value(row,"stepName")}</option>)}</select></Field><div className="lg:col-span-2 flex items-end"><SaveButton busy={busy} label="사전검사 통과 후 승인"/></div></Form>
        <Table heads={["상태","점수","프로세스·절차","화면","설계","선택 시안","액터","5대 테스트","디자인 자산","미충족 항목"]} rows={data.screenDevelopmentGates.filter(row=>!processFilter||value(row,"processCode")===processFilter).map(row=>[value(row,"gateStatus"),`${value(row,"readinessScore")}%`,`${value(row,"processCode")} · ${value(row,"stepCode")}`,value(row,"routePath"),value(row,"designNotePassed"),value(row,"selectedMockupPassed"),value(row,"actorContractPassed"),value(row,"safetyTestsPassed"),value(row,"designAssetChecked"),value(row,"failureSummary")||"-"])}/>
        <Table heads={["프로세스","순서","상위 절차","상세 절차","유형","자동화","화면·API"]} rows={selectedSteps.map(row=>[value(row,"processCode"),value(row,"stepOrder"),value(row,"parentStepCode")||"-",value(row,"stepName"),value(row,"stepType"),value(row,"automationStatus"),[value(row,"userPath"),value(row,"adminPath"),value(row,"apiContract")].filter(Boolean).join(" · ")])}/>
        <Form onSubmit={event=>void submit(event,"development/retry")} cols="lg:grid-cols-4"><Field label="실패 작업 ID"><input className={fieldClass} type="number" min="1" name="jobId" required/></Field><div className="lg:col-span-3 flex items-end"><SaveButton busy={busy} label="복구 기준 확인 후 재시도"/></div></Form>
        <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{data.processDevelopmentProgress.filter(row=>!processFilter||value(row,"processCode")===processFilter).map(row=><div key={value(row,"processCode")} className="rounded-xl border bg-white p-4"><span className="text-xs font-black text-slate-500">{value(row,"processCode")}</span><strong className="mt-1 block text-2xl text-[#052b57]">{value(row,"completionPercent")}%</strong><div className="mt-2 h-2 overflow-hidden rounded-full bg-slate-100"><div className="h-full bg-[#246beb]" style={{width:`${Math.min(Number(row.completionPercent||0),100)}%`}}/></div><p className="mt-2 text-xs text-slate-600">필수 {value(row,"verifiedJobs")}/{value(row,"requiredJobs")} · 병렬 {value(row,"parallelJobs")} · 실패 {value(row,"failedJobs")}</p></div>)}</section>
        <Table heads={["ID","절차·작업","실행","그룹","필수·가중치","상태","품질","검색 컨텍스트"]} rows={data.developmentJobs.filter(row=>!processFilter||value(row,"processCode")===processFilter).map(row=>[value(row,"jobId"),`${value(row,"stepCode")} · ${value(row,"jobName")}`,value(row,"executionMode"),value(row,"jobGroupCode")||"-",`${value(row,"required")} · ${value(row,"progressWeight")}`,`${value(row,"jobStatus")} (${value(row,"attemptCount")}/${value(row,"maxAttempts")})`,value(row,"qualityStatus"),value(row,"searchContextRef")||"-"])}/>
        <Table heads={["작업","선행 작업","조건","선행 상태"]} rows={data.jobDependencies.filter(row=>!processFilter||data.developmentJobs.some(job=>value(job,"jobId")===value(row,"jobId")&&value(job,"processCode")===processFilter)).map(row=>[`${value(row,"jobId")} · ${value(row,"jobName")}`,`${value(row,"dependsOnJobId")} · ${value(row,"dependsOnJobName")}`,value(row,"dependencyType"),value(row,"dependsOnStatus")])}/>
        <Table heads={["품질 게이트","범위","필수","최근 결과","증적"]} rows={data.qualityGates.map(gate=>{const result=data.qualityGateResults.find(row=>value(row,"gateCode")===value(gate,"gateCode")&&(!processFilter||data.developmentJobs.some(job=>value(job,"jobId")===value(row,"jobId")&&value(job,"processCode")===processFilter)));return [value(gate,"gateName"),value(gate,"gateScope"),value(gate,"mandatory"),result?`${value(result,"result")} · ${value(result,"summary")}`:"미실행",result?value(result,"evidenceRef"):"-"]})}/>
        <Table heads={["이벤트","작업 ID","상태 변경","실행기","일시"]} rows={data.developmentEvents.map(row=>[value(row,"eventType"),value(row,"jobId"),`${value(row,"fromStatus")} → ${value(row,"toStatus")}`,value(row,"workerId"),value(row,"createdAt")])}/>
      </>}

      {tab === "overview" && <div className="grid gap-5 xl:grid-cols-[1.1fr_.9fr]">
        <Panel title="개발 준비도" description="단계가 존재하고 모든 필수 시나리오가 승인된 프로세스 비율입니다."><div className="mt-4 h-4 overflow-hidden rounded-full bg-slate-100"><div className="h-full bg-[#246beb]" style={{ width: `${Math.min(readiness, 100)}%` }} /></div><div className="mt-2 flex justify-between text-sm"><b>{readiness}% 완료</b><span className="text-slate-500">준비 {readyCount} · 보완 {Math.max(data.processes.length - readyCount, 0)}</span></div></Panel>
        <Panel title="권장 등록 순서" description="순서를 지키면 권한과 테스트 참조 오류를 줄일 수 있습니다."><ol className="mt-3 grid gap-2 text-sm text-slate-700"><li>1. 액터와 기능 권한 정의</li><li>2. 실제 계정을 테넌트·프로젝트·액터에 배정</li><li>3. 프로세스 목표와 시작·완료 조건 정의</li><li>4. 액터별 상태 전이 단계 연결</li><li>5. 정상·예외·권한·격리·복구 시나리오 실행</li></ol></Panel>
        <div className="xl:col-span-2"><Table heads={["순서", "프로세스", "선행 프로세스", "단계", "산출물 검증", "테스트 승인", "종합", "판정"]} rows={data.processes.map(row => {const percent=processCompletion(row),blocked=value(row,"prerequisiteCodes")&&value(row,"status")!=="DEVELOPMENT_READY";return [value(row,"developmentOrder"),value(row, "processName"),value(row,"prerequisiteCodes")||"없음",value(row,"stepCount"),`${value(row,"verifiedArtifactCount")}/${value(row,"artifactCount")}`,`${value(row,"approvedCaseCount")}/${value(row,"caseCount")}`,`${percent}%`,value(row,"status")==="DEVELOPMENT_READY"?"개발·테스트 완료":blocked?"선행조건·검증 필요":"개발 진행 필요"]})} /></div>
      </div>}

      {tab === "actors" && <><Form onSubmit={event => void submit(event, "actors")} cols="lg:grid-cols-6"><Field label="액터 코드"><input className={fieldClass} name="actorCode" required /></Field><Field label="액터명"><input className={fieldClass} name="actorName" required /></Field><Field label="유형"><select className={fieldClass} name="actorType"><option>BUSINESS</option><option>REVIEW</option><option>APPROVAL</option><option>OPERATION</option><option>AUTOMATION</option><option>AUDIT</option></select></Field><Field label="기능 권한"><input className={fieldClass} name="capabilityCodes" placeholder="VIEW,EDIT,SUBMIT" /></Field><div className="lg:col-span-2"><Field label="목적"><input className={fieldClass} name="purpose" required /></Field></div><SaveButton busy={busy} /></Form><Table heads={["코드", "액터명", "유형", "목적", "기능 권한"]} rows={data.actors.map(row => [value(row, "actorCode"), value(row, "actorName"), value(row, "actorType"), value(row, "purpose"), value(row, "capabilityCodes")])} /></>}

      {tab === "assignments" && <><Form onSubmit={event => void submit(event, "assignments")} cols="lg:grid-cols-6"><Field label="계정 ID"><input className={fieldClass} name="accountId" required /></Field><Field label="테넌트"><input className={fieldClass} name="tenantId" defaultValue="DEFAULT" required /></Field><Field label="프로젝트"><input className={fieldClass} name="projectId" defaultValue="*" required /></Field><Field label="데이터 범위"><input className={fieldClass} name="dataScope" defaultValue="*" required /></Field><Field label="액터"><select className={fieldClass} name="actorCode" required>{data.actors.map(row => <option key={value(row, "actorCode")} value={value(row, "actorCode")}>{value(row, "actorName")} ({value(row, "actorCode")})</option>)}</select></Field><SaveButton busy={busy} label="배정" /></Form><Table heads={["계정", "테넌트", "프로젝트", "액터", "데이터 범위", "상태"]} rows={data.assignments.map(row => [value(row, "accountId"), value(row, "tenantId"), value(row, "projectId"), value(row, "actorCode"), value(row, "dataScope"), value(row, "status")])} /></>}
      {tab === "account-readiness" && <><section className="rounded-2xl border border-slate-200 bg-white p-5"><h2 className="text-lg font-black text-slate-900">액터별 실제 계정·권한·업무 연결 상태</h2><p className="mt-2 text-sm leading-6 text-slate-600">회원 계정, 시스템 권한, 프로젝트 액터 배정, 실제 업무 API가 사용하는 실행 배정의 일치 여부를 함께 확인합니다. CHECK_REQUIRED 또는 DRIFT는 업무 실행 전에 반드시 조치해야 합니다.</p></section><Table heads={["계정", "액터", "테넌트", "프로젝트", "계정 유형", "시스템 권한", "업무 연결", "준비 상태"]} rows={(data.actorAccountReadiness??[]).map(row => [value(row,"accountId"),value(row,"actorCode"),value(row,"tenantId"),value(row,"projectId"),value(row,"accountType"),value(row,"authorityCode"),value(row,"workflowBinding"),value(row,"readiness")])}/></>}

      {tab === "work-types" && <><section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h2 className="text-lg font-black text-[#052b57]">업무 종류 정의</h2><p className="mt-2 text-sm leading-6 text-slate-700">업무 종류는 프로세스 묶음과 전체 업무 보기의 최상위 분류입니다. 저장 즉시 프로세스 등록 선택지와 사용자 업무 길잡이에 반영됩니다.</p></section><Form onSubmit={event => void submit(event, "work-types")} cols="lg:grid-cols-6"><Field label="업무 종류 코드"><input className={fieldClass} name="workTypeCode" placeholder="EMISSION" pattern="[A-Z][A-Z0-9_]+" required /></Field><Field label="업무 종류명"><input className={fieldClass} name="workTypeName" required /></Field><Field label="영문명"><input className={fieldClass} name="workTypeNameEn" /></Field><Field label="표시 순서"><input className={fieldClass} name="sortOrder" type="number" defaultValue="100" min="0" required /></Field><Field label="사용 여부"><select className={fieldClass} name="useAt"><option value="Y">사용</option><option value="N">미사용</option></select></Field><SaveButton busy={busy} /><div className="lg:col-span-6"><Field label="설명"><input className={fieldClass} name="description" /></Field></div></Form><Table heads={["순서", "코드", "업무 종류명", "영문명", "설명", "사용"]} rows={(data.workTypes??[]).map(row => [value(row,"sortOrder"),value(row,"workTypeCode"),value(row,"workTypeName"),value(row,"workTypeNameEn"),value(row,"description"),value(row,"useAt")])} /></>}

      {tab === "processes" && <><Form onSubmit={event => void submit(event, "processes")} cols="lg:grid-cols-4"><Field label="프로세스 코드"><input className={fieldClass} name="processCode" required /></Field><Field label="프로세스명"><input className={fieldClass} name="processName" required /></Field><Field label="업무 종류"><select className={fieldClass} name="domainCode" required>{(data.workTypes??[]).filter(row=>value(row,"useAt")==="Y").map(row=><option key={value(row,"workTypeCode")} value={value(row,"workTypeCode")}>{value(row,"workTypeName")} ({value(row,"workTypeCode")})</option>)}</select></Field>{[["버전", "version"], ["목표", "goal"], ["시작 조건", "startCondition"], ["완료 조건", "completionCondition"]].map(([label, name]) => <Field key={name} label={label}><input className={fieldClass} name={name} defaultValue={name === "version" ? "1.0.0" : ""} required /></Field>)}<SaveButton busy={busy} /></Form><Table heads={["코드", "프로세스명", "업무 종류", "버전", "상태", "단계", "시나리오"]} rows={data.processes.map(row => [value(row, "processCode"), value(row, "processName"), value(row, "domainCode"), value(row, "version"), value(row, "status"), value(row, "stepCount"), value(row, "caseCount")])} /></>}

      {tab === "steps" && <><ProcessFilter processes={data.processes} value={processFilter} onChange={setProcessFilter} /><Form onSubmit={event => void submit(event, "steps")} cols="lg:grid-cols-4"><Field label="프로세스"><select className={fieldClass} name="processCode" required>{data.processes.map(row => <option key={value(row, "processCode")}>{value(row, "processCode")}</option>)}</select></Field><Field label="순서"><input className={fieldClass} type="number" min="1" name="stepOrder" required /></Field><Field label="단계 코드"><input className={fieldClass} name="stepCode" required /></Field><Field label="단계명"><input className={fieldClass} name="stepName" required /></Field><Field label="수행 액터"><select className={fieldClass} name="actorCode" required>{data.actors.map(row => <option key={value(row, "actorCode")} value={value(row, "actorCode")}>{value(row, "actorName")}</option>)}</select></Field><Field label="이전 상태"><input className={fieldClass} name="fromState" required /></Field><Field label="명령"><input className={fieldClass} name="commandCode" required /></Field><Field label="다음 상태"><input className={fieldClass} name="toState" required /></Field><div className="lg:col-span-2"><Field label="완료 규칙"><input className={fieldClass} name="completionRule" required /></Field></div><Field label="사용자 화면 경로"><input className={fieldClass} name="userPath" /></Field><Field label="관리자 화면 경로"><input className={fieldClass} name="adminPath" /></Field><SaveButton busy={busy} /></Form><Table heads={["프로세스", "순서", "단계", "액터", "상태 전이", "완료 규칙"]} rows={selectedSteps.map(row => [value(row, "processCode"), value(row, "stepOrder"), value(row, "stepName"), value(row, "actorCode"), `${value(row, "fromState")} → ${value(row, "toState")}`, value(row, "completionRule")])} /></>}

      {tab === "artifacts" && <><ProcessFilter processes={data.processes} value={processFilter} onChange={setProcessFilter}/><section className="grid gap-4 lg:grid-cols-2"><RuleCard title="메뉴 추가 규칙" items={["메뉴 관리 API 1회 호출로 메뉴·순서·URL·화면·기본 권한·다국어를 단일 트랜잭션 저장","DB 정본만 사용하고 프론트 하드코딩 금지","목록·업무 진입 화면만 노출하고 등록·수정·상세는 숨김 라우트","기존 URL 우선 재사용, menuCode·URL 중복은 멱등 처리","저장 성공 즉시 메뉴 캐시 무효화 후 USER·ADMIN 유형별 조회 검증"]}/><RuleCard title="디자인 적용 규칙" items={["KRDS/GOV 공통 색상·타이포·간격·상태 토큰과 공통 컴포넌트 사용","홈과 동일한 헤더·GNB·메가메뉴를 재사용하고 업무 콘텐츠만 변경","360·768·1280px 반응형과 가로 넘침 검증","키보드 이동·포커스·레이블·명도·오류 피드백 접근성 검증","폰트 단계 → 컨테이너 → 그리드 → 입력·버튼·표 밀도 순으로 자동 크기 결정"]}/></section><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-6">{["MENU","DESIGN","PAGE","API","DATA","TEST"].map(type=>{const rows=filteredArtifacts.filter(row=>value(row,"artifactType")===type),verified=rows.filter(row=>value(row,"status")==="VERIFIED").length;return <div className="rounded-xl border bg-white p-4" key={type}><span className="text-xs font-black text-slate-500">{type}</span><strong className="mt-1 block text-2xl text-[#052b57]">{verified}/{rows.length}</strong><p className="text-xs text-slate-500">검증 완료</p></div>})}</div><Form onSubmit={event=>void submit(event,"artifacts")} cols="lg:grid-cols-4"><Field label="프로세스"><select className={fieldClass} name="processCode" required>{data.processes.map(row=><option key={value(row,"processCode")}>{value(row,"processCode")}</option>)}</select></Field><Field label="산출물 코드"><input className={fieldClass} name="artifactCode" required/></Field><Field label="유형"><select className={fieldClass} name="artifactType"><option>MENU</option><option>DESIGN</option><option>PAGE</option><option>API</option><option>DATA</option><option>AUTHORITY</option><option>RULE</option><option>NOTIFICATION</option><option>AUDIT</option><option>TEST</option><option>OPERATION</option></select></Field><Field label="산출물명"><input className={fieldClass} name="artifactName" required/></Field><Field label="단계 코드"><input className={fieldClass} name="stepCode"/></Field><Field label="경로"><input className={fieldClass} name="targetPath"/></Field><Field label="계약 참조"><input className={fieldClass} name="contractRef"/></Field><Field label="담당 액터"><select className={fieldClass} name="ownerActorCode">{data.actors.map(row=><option key={value(row,"actorCode")} value={value(row,"actorCode")}>{value(row,"actorName")}</option>)}</select></Field><Field label="상태"><select className={fieldClass} name="status"><option>PLANNED</option><option>IN_PROGRESS</option><option>IMPLEMENTED</option><option>IN_REVIEW</option><option>VERIFIED</option><option>BLOCKED</option></select></Field><div className="lg:col-span-2"><Field label="인수 기준"><input className={fieldClass} name="acceptanceCriteria" required/></Field></div><Field label="검증 증적"><input className={fieldClass} name="evidenceRef" placeholder="테스트·로그·문서 경로"/></Field><SaveButton busy={busy}/></Form><Table heads={["유형","산출물","단계","담당","상태","경로·계약","인수 기준","증적"]} rows={filteredArtifacts.map(row=>[value(row,"artifactType"),value(row,"artifactName"),value(row,"stepCode"),value(row,"ownerActorCode"),value(row,"status"),value(row,"targetPath")||value(row,"contractRef"),value(row,"acceptanceCriteria"),value(row,"evidenceRef")])}/></>}

      {tab==="design"&&<><section className="grid gap-4 sm:grid-cols-3 lg:grid-cols-6">{[["테마","themes"],["클래스셋","classSets"],["섹션","sections"],["컴포넌트","components"],["페이지","pages"],["매핑","mappings"]].map(([label,key])=><div className="rounded-xl border bg-white p-4" key={key}><span className="text-xs font-bold text-slate-500">{label}</span><strong className="mt-1 block text-2xl text-[#052b57]">{value(design.counts,key)}</strong></div>)}</section><section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="font-black text-[#052b57]">화면 개발 착수 게이트</h3><p className="mt-1 text-sm text-slate-700">활성 테마와 등록 섹션을 선택하고 컴포넌트 의미·속성·디자인 지문을 비교합니다. 동일하면 REUSED, 없을 때만 CREATED로 등록하며 페이지·섹션 매핑과 증적을 한 트랜잭션으로 저장합니다.</p></section><Form onSubmit={async event=>{event.preventDefault();const form=event.currentTarget;await post("design-assets/preflight",Object.fromEntries(new FormData(form).entries()));await loadDesign();}} cols="lg:grid-cols-4"><Field label="페이지 ID"><input className={fieldClass} name="pageId" required/></Field><Field label="페이지명"><input className={fieldClass} name="pageName" required/></Field><Field label="라우트"><input className={fieldClass} name="routePath" placeholder="/emission/..." required/></Field><Field label="도메인"><input className={fieldClass} name="domainCode" defaultValue="COMMON" required/></Field><Field label="테마"><select className={fieldClass} name="themeId">{design.themes.map(row=><option key={value(row,"themeId")} value={value(row,"themeId")}>{value(row,"themeName")}</option>)}</select></Field><Field label="섹션"><select className={fieldClass} name="sectionId">{design.sections.map(row=><option key={value(row,"sectionId")} value={value(row,"sectionId")}>{value(row,"sectionName")}</option>)}</select></Field><Field label="컴포넌트명"><input className={fieldClass} name="componentName" required/></Field><Field label="컴포넌트 유형"><input className={fieldClass} name="componentType" placeholder="TABLE, FORM, CARD" required/></Field><Field label="카테고리"><input className={fieldClass} name="category" defaultValue="COMMON"/></Field><Field label="디자인 참조"><input className={fieldClass} name="designReference" defaultValue="KRDS_GOV_DEFAULT"/></Field><div className="lg:col-span-2"><Field label="Props Schema JSON"><input className={fieldClass} name="propsSchema" defaultValue="{}"/></Field></div><SaveButton busy={busy} label="사전검사·재사용/등록"/></Form><Table heads={["페이지","경로","테마","섹션","컴포넌트","판정","실행자","일시"]} rows={design.recentPreflights.map(row=>[value(row,"pageId"),value(row,"routePath"),value(row,"themeId"),value(row,"sectionId"),value(row,"componentId"),value(row,"decision"),value(row,"executedBy"),value(row,"executedAt")])}/><Table heads={["섹션","유형","레이아웃","반응형","접근성"]} rows={design.sections.map(row=>[value(row,"sectionName"),value(row,"sectionType"),value(row,"layoutContract"),value(row,"responsiveContract"),value(row,"accessibilityContract")])}/></>}

      {tab==="rules"&&<><section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="text-lg font-black text-[#052b57]">전역 개발 완료 규칙</h3><p className="mt-1 text-sm text-slate-700">모든 프로세스에 공통 적용됩니다. 필수 규칙의 검증 방법과 증적을 산출물 인수 기준에 포함해야 합니다.</p></section><Table heads={["그룹","규칙","설명","검증 방법","소스 근거"]} rows={data.developmentRules.map(row=>[value(row,"ruleGroup"),value(row,"ruleName"),value(row,"ruleDescription"),value(row,"verificationMethod"),value(row,"sourceRef")])}/></>}

      {tab === "simulation" && <><ProcessFilter processes={data.processes} value={processFilter} onChange={setProcessFilter} /><div className="grid gap-4 xl:grid-cols-2"><Form onSubmit={event => void submit(event, "cases")} cols="sm:grid-cols-2"><Field label="시나리오 코드"><input className={fieldClass} name="caseCode" required /></Field><Field label="프로세스"><select className={fieldClass} name="processCode">{data.processes.map(row => <option key={value(row, "processCode")}>{value(row, "processCode")}</option>)}</select></Field><Field label="시나리오명"><input className={fieldClass} name="caseName" required /></Field><Field label="유형"><select className={fieldClass} name="caseType"><option>HAPPY_PATH</option><option>EXCEPTION</option><option>AUTHORITY</option><option>ISOLATION</option><option>RECOVERY</option></select></Field><Field label="사전 조건"><textarea className={`${fieldClass} h-24 py-2`} name="preconditions" required /></Field><Field label="실행 단계 JSON"><textarea className={`${fieldClass} h-24 py-2`} name="stepsJson" defaultValue="[]" required /></Field><div className="sm:col-span-2"><Field label="검증 조건 JSON"><textarea className={`${fieldClass} h-20 py-2`} name="assertionsJson" defaultValue="[]" required /></Field></div><SaveButton busy={busy} label="시나리오 저장" /></Form><Form onSubmit={event => void submit(event, "runs")} cols="sm:grid-cols-2"><Field label="시나리오"><select className={fieldClass} name="caseCode">{data.cases.map(row => <option key={value(row, "caseCode")}>{value(row, "caseCode")}</option>)}</select></Field><Field label="결과"><select className={fieldClass} name="result"><option>PASSED</option><option>FAILED</option><option>BLOCKED</option></select></Field><Field label="실패 사유"><textarea className={`${fieldClass} h-24 py-2`} name="failureReason" /></Field><Field label="증적 JSON"><textarea className={`${fieldClass} h-24 py-2`} name="evidenceJson" defaultValue="{}" /></Field><SaveButton busy={busy} label="실행 결과 기록" /></Form></div><Table heads={["시나리오", "프로세스", "이름", "유형", "상태"]} rows={selectedCases.map(row => [value(row, "caseCode"), value(row, "processCode"), value(row, "caseName"), value(row, "caseType"), value(row, "status")])} /></>}
    </div>
  </AdminPageShell>;
}

function CommonFeaturePackagePanel({bindings,busy,installations,onPost,packages,processCode,runs}:{bindings:Row[];busy:boolean;installations:Row[];onPost:(path:string,body:Record<string,unknown>)=>Promise<void>;packages:Row[];processCode:string;runs:Row[]}) {
  const visibleBindings=bindings.filter(row=>!processCode||value(row,"processCode")===processCode);
  const latestRuns=processCode?runs.filter(row=>value(row,"processCode")===processCode):runs;
  return <div className="space-y-5">
    <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5">
      <h3 className="text-lg font-black text-[#052b57]">설치형 공통 특수기능</h3>
      <p className="mt-1 text-sm leading-6 text-slate-700">화면은 엑셀·AI 매핑·단위 변환·승인·PDF·OCR 같은 기능을 직접 복제하지 않고 버전이 있는 공통 패키지에 연결합니다. API·DB·UI·이벤트·권한·테스트 계약과 필수 의존성이 함께 설치됩니다.</p>
      <button className="mt-4 rounded-lg bg-[#052b57] px-4 py-3 font-bold text-white disabled:opacity-50" disabled={busy||!processCode} onClick={()=>void onPost("design/validate",{processCode})} type="button">선택 프로세스 정합성 검사</button>
    </section>
    <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{[["등록 패키지",packages.length],["플랫폼 설치",installations.filter(row=>value(row,"installationStatus")==="INSTALLED").length],["화면 연결",visibleBindings.length],["설계 차단",latestRuns.filter(row=>value(row,"validationStatus")==="BLOCKED").length]].map(([label,metric])=><article className="rounded-xl border bg-white p-4" key={String(label)}><span className="text-sm font-bold text-slate-500">{label}</span><strong className="mt-1 block text-2xl text-[#052b57]">{metric}</strong></article>)}</section>
    {packages.some(row=>!installations.some(item=>value(item,"featureCode")===value(row,"featureCode")&&value(item,"projectScope")==="PLATFORM"))?<div className="flex flex-wrap gap-2">{packages.filter(row=>!installations.some(item=>value(item,"featureCode")===value(row,"featureCode")&&value(item,"projectScope")==="PLATFORM")).map(row=><button className="rounded bg-[#246beb] px-3 py-2 text-xs font-bold text-white disabled:opacity-50" disabled={busy} key={value(row,"featureCode")} onClick={()=>void onPost("common-features/install",{featureCode:value(row,"featureCode"),projectScope:"PLATFORM",configuration:{}})} type="button">{value(row,"featureCode")} 설치</button>)}</div>:null}
    <Table heads={["기능 코드·버전","분류","설명","API·데이터 계약","UI·테스트 계약","설치 상태"]} rows={packages.map(row=>{const installed=installations.find(item=>value(item,"featureCode")===value(row,"featureCode")&&value(item,"projectScope")==="PLATFORM");return [`${value(row,"featureCode")} · ${value(row,"featureVersion")}`,value(row,"featureCategory"),value(row,"description"),`${value(row,"apiContract")} / ${value(row,"dataContract")}`,`${value(row,"uiContract")} / ${value(row,"testContract")}`,installed?`${value(installed,"installationStatus")} ${value(installed,"installedVersion")}`:"미설치"]})}/>
    <Table heads={["프로세스·단계","대상","라우트","공통 기능","필수"]} rows={visibleBindings.map(row=>[`${value(row,"processCode")} · ${value(row,"stepCode")}`,value(row,"audience"),value(row,"routePath"),value(row,"featureCode"),value(row,"requiredYn")])}/>
    <Table heads={["검사 실행","프로세스","판정","차단","경고","검사 결과","실행 시각"]} rows={latestRuns.map(row=>[value(row,"validationRunId"),value(row,"processCode"),value(row,"validationStatus"),value(row,"blockerCount"),value(row,"warningCount"),value(row,"resultJson"),value(row,"executedAt")])}/>
  </div>;
}

function ActorProcessMenuPanel({ en, rows, summary }: { en: boolean; rows: Row[]; summary: Row }) {
  const cards = [
    [en?"Navigable menus":"실행 메뉴",value(summary,"navigableMenuCount")||String(rows.length)],
    [en?"Bound menus":"연결 완료",value(summary,"boundMenuCount")||"0"],
    [en?"Missing bindings":"미연결",value(summary,"missingMenuCount")||"0"],
    [en?"Processes":"연결 프로세스",value(summary,"connectedProcessCount")||"0"],
    [en?"Actors":"연결 액터",value(summary,"connectedActorCount")||"0"],
  ];
  return <div className="space-y-5">
    <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5"><h3 className="text-lg font-black text-[#052b57]">{en?"Actor, process, and menu ownership":"액터·프로세스·메뉴 전체 귀속"}</h3><p className="mt-2 text-sm leading-6 text-slate-700">{en?"Every navigable menu is bound to one process step and responsible actor. Unavailable leaf menus are excluded from customer navigation until implemented.":"실행 가능한 모든 메뉴를 하나의 프로세스 단계와 책임 액터에 연결합니다. URL이 없는 최종 메뉴는 구현될 때까지 고객 메뉴에서 제외합니다."}</p></section>
    <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-5">{cards.map(([label,metric])=><article className="rounded-2xl border bg-white p-5" key={label}><span className="text-sm font-bold text-slate-500">{label}</span><strong className="mt-2 block text-3xl font-black text-[#052b57]">{metric}</strong></article>)}</section>
    <Table heads={en?["Menu","Audience","Process","Step","Actor","Status"]:["메뉴·URL","대상","프로세스","단계","책임 액터","상태"]} rows={rows.map(row=>[`${value(row,"menuName")} (${value(row,"menuCode")}) · ${value(row,"menuUrl")}`,value(row,"audience"),value(row,"processCode"),value(row,"stepCode"),value(row,"actorCode"),value(row,"bindingStatus")])}/>
  </div>;
}

function CustomerJourneyGatePanel({ en, rows, summary }: { en: boolean; rows: Row[]; summary: Row }) {
  const cards = [
    [en ? "Total gaps" : "전체 미충족", value(summary,"totalGaps") || "0"],
    [en ? "Release blockers" : "배포 차단", value(summary,"blockerGaps") || "0"],
    [en ? "Dead menu targets" : "죽은 메뉴", value(summary,"deadMenuGaps") || "0"],
    [en ? "Invalid task routes" : "업무 경로 누락", value(summary,"taskRouteGaps") || "0"],
    [en ? "Registration gaps" : "등록 요건 미충족", value(summary,"registrationGaps") || "0"],
  ];
  return <div className="space-y-5">
    <section className="rounded-2xl border border-emerald-200 bg-emerald-50 p-5"><h3 className="text-lg font-black text-[#052b57]">{en?"Automated customer journey release gate":"고객 여정 자동 배포 게이트"}</h3><p className="mt-2 text-sm leading-6 text-slate-700">{en?"Builds fail when a visible leaf menu has no route, an actionable task has no workspace, or a generated screen loses authority and test contracts.":"노출된 최종 메뉴에 URL이 없거나 실행 가능한 Task에 업무 화면이 없거나 생성 화면의 권한·테스트 계약이 깨지면 빌드를 실패시킵니다."}</p></section>
    <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-5">{cards.map(([label,metric])=><article className="rounded-2xl border bg-white p-5" key={label}><span className="text-sm font-bold text-slate-500">{label}</span><strong className="mt-2 block text-3xl font-black text-[#052b57]">{metric}</strong></article>)}</section>
    <Table heads={en?["Severity","Type","Object","Target","Reason","Required action"]:["심각도","유형","대상","경로","발견 사유","필수 조치"]} rows={rows.map(row=>[value(row,"severity"),value(row,"gapType"),`${value(row,"objectName")} (${value(row,"objectCode")})`,value(row,"targetUrl")||"-",value(row,"reason"),value(row,"remediation")])}/>
  </div>;
}

function ProjectRegistrationCoveragePanel({ en, rows, summary }: { en: boolean; rows: Row[]; summary: Row }) {
  const cards = [
    [en ? "Total requirements" : "전체 요건", value(summary, "total") || String(rows.length)],
    [en ? "Ready to reuse" : "즉시 재사용", value(summary, "supported") || "0"],
    [en ? "Connection required" : "연결·보강 필요", value(summary, "partial") || "0"],
    [en ? "New implementation" : "신규 구현", value(summary, "missing") || "0"],
    [en ? "Coverage" : "현재 충족도", `${value(summary, "averageScore") || "0"}%`],
  ];
  const statusClass = (status:string) => status === "SUPPORTED" ? "bg-emerald-100 text-emerald-800" : status === "PARTIAL" ? "bg-amber-100 text-amber-800" : "bg-red-100 text-red-800";
  return <div className="space-y-5">
    <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5">
      <h3 className="text-lg font-black text-[#052b57]">{en ? "Emission project registration coverage" : "배출량 프로젝트 등록 요건 전수 점검"}</h3>
      <p className="mt-2 text-sm leading-6 text-slate-700">{en ? "Membership, organization, authority, common codes, menus, calculation policies, validation, reporting, and audit are controlled as one registration contract." : "회원가입·기업·권한·공통코드·메뉴뿐 아니라 조직경계, 산정기준, 수집계획, 검증·승인, 보고·감사까지 하나의 등록 계약으로 관리합니다."}</p>
      <p className="mt-2 text-sm font-bold text-[#174ea6]">{en ? "Create-phase fields stay in the registration wizard; later policies belong to project settings. Only reusable administrator policies receive standalone menus." : "생성 단계 항목은 등록 마법사에, 이후 정책은 프로젝트 설정에 둡니다. 반복 관리가 필요한 관리자 정책만 독립 메뉴로 만듭니다."}</p>
    </section>
    <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-5">{cards.map(([label, metric]) => <article key={label} className="rounded-2xl border bg-white p-5"><span className="text-sm font-bold text-slate-500">{label}</span><strong className="mt-2 block text-3xl font-black text-[#052b57]">{metric}</strong></article>)}</section>
    <section className="overflow-hidden rounded-2xl border bg-white"><div className="overflow-x-auto"><table className="w-full min-w-[1500px] text-left text-sm"><thead className="bg-slate-100"><tr>{(en ? ["Group","Requirement","Phase","Status","User route","Admin route","Data / code","Actors","Acceptance criteria","Action"] : ["구분","필수 정보·기능","적용 단계","현황","사용자 화면","관리 화면","데이터·공통코드","담당 액터","완료 기준","조치"]).map(head => <th key={head} className="px-4 py-3 font-bold text-slate-700">{head}</th>)}</tr></thead><tbody>{rows.map(row => { const status=value(row,"implementationStatus"); return <tr key={value(row,"requirementCode")} className="border-t align-top"><td className="px-4 py-4 font-bold">{value(row,"requirementGroup")}</td><td className="px-4 py-4"><b>{value(row,"requirementName")}</b><div className="mt-1 font-mono text-xs text-slate-500">{value(row,"requirementCode")}</div></td><td className="px-4 py-4">{value(row,"lifecyclePhase")}</td><td className="px-4 py-4"><span className={`rounded-full px-3 py-1 text-xs font-black ${statusClass(status)}`}>{status}</span></td><td className="px-4 py-4"><a className="font-semibold text-blue-700 hover:underline" href={value(row,"targetRoute")}>{value(row,"targetRoute")}</a></td><td className="px-4 py-4"><a className="font-semibold text-blue-700 hover:underline" href={value(row,"managementRoute")}>{value(row,"managementRoute")}</a></td><td className="max-w-[220px] px-4 py-4 text-xs leading-5"><b>{value(row,"dataOwner")}</b><div className="text-slate-500">{value(row,"commonCodeGroup") || "-"}</div></td><td className="max-w-[210px] px-4 py-4 text-xs leading-5">{value(row,"actorCodes")}</td><td className="max-w-[320px] px-4 py-4 leading-6 text-slate-600">{value(row,"acceptanceCriteria")}</td><td className="px-4 py-4"><b>{value(row,"recommendedAction")}</b><div className="mt-1 max-w-[260px] text-xs leading-5 text-slate-500">{value(row,"implementationNote")}</div></td></tr>})}</tbody></table></div></section>
  </div>;
}

function ProfessionalReadinessPanel({ en, rows, summary }: { en: boolean; rows: Row[]; summary: Row }) {
  const cards = [
    [en ? "Average readiness" : "평균 전문가 준비도", `${value(summary, "averageScore") || "0"}%`],
    [en ? "Expert-ready" : "전문가 운영 가능", value(summary, "expertReadyProcesses") || "0"],
    [en ? "High-risk processes" : "우선 보완 프로세스", value(summary, "highRiskProcesses") || "0"],
    [en ? "Total processes" : "전체 프로세스", value(summary, "totalProcesses") || String(rows.length)],
  ];
  return <div className="space-y-5">
    <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5">
      <h3 className="text-lg font-black text-[#052b57]">{en ? "Professional process governance audit" : "전문가 수준 프로세스 거버넌스 감사"}</h3>
      <p className="mt-2 text-sm leading-6 text-slate-700">{en ? "A process is expert-ready only when ownership, RACI, segregation of duties, regulatory basis, SLA, evidence, five safety scenarios, verified deliverables, and review lifecycle are all controlled." : "소유자·RACI 책임, 직무분리, 규정 근거, SLA, 필수 증적, 5종 안전 시나리오, 검증된 산출물, 정기 검토 생명주기를 모두 갖춰야 전문가 운영 가능으로 판정합니다."}</p>
    </section>
    <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{cards.map(([label, metric]) => <article key={label} className="rounded-2xl border bg-white p-5"><span className="text-sm font-bold text-slate-500">{label}</span><strong className="mt-2 block text-3xl font-black text-[#052b57]">{metric}</strong></article>)}</section>
    <section className="overflow-hidden rounded-2xl border bg-white">
      <div className="border-b px-5 py-4"><h3 className="font-black text-slate-900">{en ? "Process remediation queue" : "프로세스 보완 우선순위"}</h3><p className="mt-1 text-sm text-slate-500">{en ? "Lower scores are shown first." : "준비도가 낮은 프로세스부터 표시합니다."}</p></div>
      <div className="overflow-x-auto"><table className="w-full min-w-[980px] text-left text-sm"><thead className="bg-slate-100"><tr>{(en ? ["Process", "Lifecycle", "Risk", "Score", "Steps", "Scenario types", "Approved cases", "Gaps"] : ["프로세스", "생명주기", "위험도", "준비도", "단계", "시나리오 유형", "승인 테스트", "보완 항목"]).map(head => <th key={head} className="px-4 py-3 font-bold text-slate-700">{head}</th>)}</tr></thead><tbody>{rows.map(row => { const score = Number(row.readinessScore ?? 0); return <tr key={value(row, "processCode")} className="border-t align-top"><td className="px-4 py-4"><b className="text-slate-900">{value(row, "processName")}</b><div className="mt-1 font-mono text-xs text-slate-500">{value(row, "processCode")}</div></td><td className="px-4 py-4">{value(row, "lifecycleStatus")}</td><td className="px-4 py-4">{value(row, "riskLevel")}</td><td className="px-4 py-4"><span className={`rounded-full px-3 py-1 font-black ${score === 100 ? "bg-emerald-100 text-emerald-800" : score >= 80 ? "bg-amber-100 text-amber-800" : "bg-red-100 text-red-800"}`}>{score}%</span></td><td className="px-4 py-4">{value(row, "stepCount")}</td><td className="px-4 py-4">{value(row, "scenarioTypeCount")}/5</td><td className="px-4 py-4">{value(row, "approvedCaseCount")}/{value(row, "caseCount")}</td><td className="max-w-[360px] px-4 py-4 leading-6 text-slate-600">{value(row, "readinessGaps") || (en ? "No gaps" : "보완 항목 없음")}</td></tr>; })}</tbody></table></div>
    </section>
  </div>;
}

function ProfessionalScreenContractPanel({ en, rows, summary, assemblies }: { en: boolean; rows: Row[]; summary: Row; assemblies:Row[] }) {
  const cards = [
    [en ? "Governed screens" : "계약 화면", value(summary, "totalScreens") || String(rows.length)],
    [en ? "Complete" : "완료", value(summary, "completeScreens") || "0"],
    [en ? "Blocked" : "개발 차단", value(summary, "blockedScreens") || "0"],
    [en ? "Average score" : "평균 완성도", `${value(summary, "averageScore") || "0"}%`],
  ];
  return <div className="space-y-5">
    <section className="rounded-2xl border border-blue-200 bg-blue-50 p-5">
      <h3 className="text-lg font-black text-[#052b57]">{en ? "Professional screen completion contract" : "전문 업무 화면 완성 계약"}</h3>
      <p className="mt-2 text-sm leading-6 text-slate-700">{en ? "A screen cannot enter development approval until real API, persistence, actor isolation, responsive behavior, accessibility, exceptional states, and browser E2E evidence reach 100%." : "실제 API, DB 영속성, 액터·테넌트 격리, 반응형, 접근성, 예외 상태와 브라우저 E2E 증적이 모두 검증되어 100점이 되기 전에는 자동 개발 승인을 차단합니다."}</p>
    </section>
    <section className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{cards.map(([label, metric]) => <article key={label} className="rounded-2xl border bg-white p-5"><span className="text-sm font-bold text-slate-500">{label}</span><strong className="mt-2 block text-3xl font-black text-[#052b57]">{metric}</strong></article>)}</section>
    <section className="overflow-hidden rounded-2xl border bg-white"><div className="overflow-x-auto"><table className="w-full min-w-[1200px] text-left text-sm"><thead className="bg-slate-100"><tr>{(en ? ["Score","Process step","Audience","Screen","Actor","Required fields","Commands","Verification gaps"] : ["점수","프로세스 단계","대상","화면·경로","액터","필수 데이터","업무 명령","미검증 항목"]).map(head=><th className="px-4 py-3 font-bold text-slate-700" key={head}>{head}</th>)}</tr></thead><tbody>{rows.map(row=>{const score=Number(row.readinessScore||0);return <tr className="border-t align-top" key={value(row,"contractId")}><td className="px-4 py-4"><span className={`rounded-full px-3 py-1 font-black ${score===100?"bg-emerald-100 text-emerald-800":"bg-red-100 text-red-800"}`}>{score}%</span></td><td className="px-4 py-4"><b>{value(row,"stepCode")}</b><div className="mt-1 text-xs text-slate-500">{value(row,"businessPurpose")}</div></td><td className="px-4 py-4">{value(row,"audience")}</td><td className="px-4 py-4"><a className="font-bold text-blue-700 hover:underline" href={value(row,"routePath")}>{value(row,"screenName")}</a><div className="mt-1 font-mono text-xs text-slate-500">{value(row,"routePath")}</div></td><td className="px-4 py-4">{value(row,"actorCode")}</td><td className="max-w-[260px] px-4 py-4 text-xs leading-5 text-slate-600">{value(row,"fieldContract")}</td><td className="max-w-[220px] px-4 py-4 text-xs leading-5 text-slate-600">{value(row,"commandContract")}</td><td className="max-w-[320px] px-4 py-4 font-semibold text-red-700">{value(row,"readinessGaps")||"-"}</td></tr>})}</tbody></table></div></section>
    <section className="overflow-hidden rounded-2xl border bg-white"><div className="border-b p-5"><h3 className="font-black text-[#052b57]">{en?"Full-stack asset assembly":"프론트·백엔드·디자인 자산 조립"}</h3><p className="mt-1 text-sm text-slate-500">{en?"Reuse registered assets first and route only missing assets to their management pages.":"등록 자산을 먼저 재사용하고 부족한 자산만 해당 관리 화면의 보강 대상으로 전달합니다."}</p></div><div className="overflow-x-auto"><table className="w-full min-w-[1000px] text-left text-sm"><thead className="bg-slate-100"><tr>{(en?["Screen","Score","Ready","Gaps","Assembly status"]:["화면","조립 점수","준비 자산","부족 자산","계층별 상태"]).map(head=><th className="px-4 py-3 font-bold" key={head}>{head}</th>)}</tr></thead><tbody>{assemblies.map(row=><tr className="border-t" key={value(row,"contractId")}><td className="px-4 py-4"><b>{value(row,"screenName")}</b><div className="font-mono text-xs text-slate-500">{value(row,"routePath")}</div></td><td className="px-4 py-4 font-black text-blue-700">{value(row,"assemblyScore")}%</td><td className="px-4 py-4">{value(row,"readyAssetCount")}/{value(row,"assetCount")}</td><td className="px-4 py-4">{value(row,"gapAssetCount")}</td><td className="max-w-[480px] px-4 py-4 text-xs leading-5 text-slate-600">{value(row,"assemblyStatus")||"-"}</td></tr>)}</tbody></table></div></section>
  </div>;
}

function Field({ label, children }: { label: string; children: ReactNode }) { return <label className="block"><span className="mb-1 block text-xs font-bold text-slate-600">{label}</span>{children}</label>; }
function Form({ onSubmit, cols, children }: { onSubmit: (event: FormEvent<HTMLFormElement>) => void; cols: string; children: ReactNode }) { return <form className={`grid gap-3 rounded-2xl border bg-white p-5 ${cols}`} onSubmit={onSubmit}>{children}</form>; }
function SaveButton({ busy, label = "저장" }: { busy: boolean; label?: string }) { return <button disabled={busy} className="h-11 self-end rounded-lg bg-[#246beb] px-4 font-bold text-white disabled:opacity-50" type="submit">{busy ? "처리 중..." : label}</button>; }
function Panel({ title, description, children }: { title: string; description: string; children: ReactNode }) { return <section className="rounded-2xl border bg-white p-5"><h3 className="text-lg font-black text-slate-900">{title}</h3><p className="mt-1 text-sm text-slate-500">{description}</p>{children}</section>; }
function RuleCard({title,items}:{title:string;items:string[]}){return <section className="rounded-2xl border bg-white p-5"><h3 className="text-lg font-black text-[#052b57]">{title}</h3><ol className="mt-3 space-y-2 text-sm leading-6 text-slate-700">{items.map((item,index)=><li key={item}><b className="mr-2 text-blue-700">{index+1}.</b>{item}</li>)}</ol></section>}
function ProcessFilter({ processes, value: selected, onChange }: { processes: Row[]; value: string; onChange: (value: string) => void }) { return <div className="flex items-center gap-3 rounded-xl border bg-white p-4"><b className="text-sm">프로세스 필터</b><select className={`${fieldClass} max-w-md`} value={selected} onChange={event => onChange(event.target.value)}><option value="">전체 프로세스</option>{processes.map(row => <option key={value(row, "processCode")} value={value(row, "processCode")}>{value(row, "processName")} ({value(row, "processCode")})</option>)}</select></div>; }
function Table({ heads, rows }: { heads: string[]; rows: string[][] }) { return <section className="overflow-hidden rounded-2xl border bg-white"><div className="overflow-x-auto"><table className="w-full min-w-[900px] text-left text-sm"><thead className="bg-slate-100"><tr>{heads.map(head => <th key={head} className="px-4 py-3 font-bold text-slate-700">{head}</th>)}</tr></thead><tbody>{rows.length ? rows.map((row, index) => <tr key={index} className="border-t hover:bg-slate-50">{row.map((cell, cellIndex) => <td key={cellIndex} className="max-w-[360px] px-4 py-3 text-slate-700">{cell || "-"}</td>)}</tr>) : <tr><td className="px-4 py-10 text-center text-slate-500" colSpan={heads.length}>등록된 항목이 없습니다.</td></tr>}</tbody></table></div></section>; }
